  | { type: 'TRACK.PAUSE' }
  | { type: 'VOL.UP' }
  | { type: 'VOL.DOWN' };

export const player = setup({
  types: {
    events: {} as Ev,
  },
}).createMachine({
  id: 'player',
  type: 'parallel',
  states: {
    transport: {
      initial: 'paused',
      states: {
        paused: { on: { 'TRACK.PLAY': 'playing' } },
        playing: { on: { 'TRACK.PAUSE': 'paused' } },
      },
    },
    volume: {
      initial: 'mid',
      states: {
        low: { on: { 'VOL.UP': 'mid' } },
        mid: {
          on: { 'VOL.UP': 'high', 'VOL.DOWN': 'low' },
        },
        high: { on: { 'VOL.DOWN': 'mid' } },
      },
    },
  },
