import { setup, fromTransition } from 'xstate';

interface CartItem {
  sku: string;
  qty: number;
}

interface CartState {
  items: CartItem[];
}

type CartEvent =
  | { type: 'ADD'; sku: string; qty: number }
  | { type: 'REMOVE'; sku: string }
  | { type: 'CLEAR' };

const cartLogic = fromTransition(
  (state: CartState, event: CartEvent): CartState => {
    switch (event.type) {
      case 'ADD': {
        const existing = state.items.find((i) => i.sku === event.sku);
        if (existing) {
          return {
            items: state.items.map((i) =>
              i.sku === event.sku ? { ...i, qty: i.qty + event.qty } : i
            ),
          };
        }
        return {
          items: [...state.items, { sku: event.sku, qty: event.qty }],
        };
      }
      case 'REMOVE':
        return { items: state.items.filter((i) => i.sku !== event.sku) };
      case 'CLEAR':
        return { items: [] };
      default:
        return state;
    }
  },
  { items: [] }
);

export const cartParent = setup({
  types: {
    events: {} as CartEvent,
  },
  actors: { cartLogic },
}).createMachine({
  id: 'cartParent',
  invoke: { id: 'cart', src: 'cartLogic' },
});
