import { setup, fromTransition } from 'xstate';

interface LogEntry {
  level: 'info' | 'warn' | 'error';
  message: string;
}

interface LogState {
  entries: LogEntry[];
}

type LogEvent =
  | { type: 'LOG'; entry: LogEntry }
  | { type: 'CLEAR' };

